import React, { useRef, useState, useCallback } from "react";
import Webcam from "react-webcam";
import api from "../api";
import toast from "react-hot-toast";

const COURSES = [
  "Computer Science", "Information Technology", "Software Engineering",
  "Data Science", "Electrical Engineering", "Mechanical Engineering",
  "Business Administration", "Accounting", "Medicine", "Law",
];

export default function RegisterStudent() {
  const webcamRef   = useRef(null);
  const [studentId, setStudentId] = useState("");
  const [name,      setName]      = useState("");
  const [course,    setCourse]    = useState("");
  const [snapshot,  setSnapshot]  = useState(null);   // base64 string
  const [cameraOn,  setCameraOn]  = useState(false);
  const [loading,   setLoading]   = useState(false);

  // ── capture ────────────────────────────────────────────────────────────────
  const capturePhoto = useCallback(() => {
    if (!webcamRef.current) {
      toast.error("Camera not ready");
      return;
    }
    const img = webcamRef.current.getScreenshot({ width: 640, height: 480 });
    if (!img) {
      toast.error("Could not capture — allow camera access and try again");
      return;
    }
    setSnapshot(img);
    setCameraOn(false);
    toast.success("Photo captured!");
  }, []);

  // ── submit ─────────────────────────────────────────────────────────────────
  const handleSubmit = async (e) => {
    e.preventDefault();

    // Client-side validation with clear messages
    if (!studentId.trim()) return toast.error("Student ID is required");
    if (!name.trim())       return toast.error("Name is required");
    if (!course)            return toast.error("Please select a course");
    if (!snapshot)          return toast.error("Please capture a face photo first");

    setLoading(true);
    try {
      const payload = {
        studentId: studentId.trim(),
        name:      name.trim(),
        course:    course,
        image:     snapshot,          // already a base64 data-URL from react-webcam
      };

      console.log("Sending registration:", {
        studentId: payload.studentId,
        name:      payload.name,
        course:    payload.course,
        imageLen:  payload.image?.length ?? 0,   // sanity check
      });

      const res = await api.post("/api/students/register", payload);
      toast.success(res.data.message || "Registered!");

      // reset form
      setStudentId("");
      setName("");
      setCourse("");
      setSnapshot(null);

    } catch (err) {
      const msg = err.response?.data?.error || err.message || "Registration failed";
      toast.error(msg);
      console.error("Registration error:", err.response?.data || err);
    } finally {
      setLoading(false);
    }
  };

  // ── render ─────────────────────────────────────────────────────────────────
  return (
    <div className="two-col">

      {/* ── LEFT: form ── */}
      <div className="card">
        <div className="card-title">✏️ Student Information</div>

        <form onSubmit={handleSubmit}>
          <div className="form-grid">
            <div className="form-group">
              <label>Student ID / Reg Number</label>
              <input
                value={studentId}
                onChange={e => setStudentId(e.target.value)}
                placeholder="e.g. CS/2023/001"
              />
            </div>

            <div className="form-group">
              <label>Full Name</label>
              <input
                value={name}
                onChange={e => setName(e.target.value)}
                placeholder="e.g. John Doe"
              />
            </div>

            <div className="form-group full">
              <label>Course / Programme</label>
              <select value={course} onChange={e => setCourse(e.target.value)}>
                <option value="">— Select a course —</option>
                {COURSES.map(c => <option key={c} value={c}>{c}</option>)}
              </select>
            </div>
          </div>

          <hr className="divider" />

          {/* ── camera area ── */}
          <div className="section-label">Biometric Face Photo</div>

          {!cameraOn && !snapshot && (
            <div className="empty-state" style={{
              padding: "28px", background: "var(--bg3)",
              borderRadius: "12px", marginBottom: "16px"
            }}>
              <div className="icon">📷</div>
              <p>Camera not active — click "Open Camera" below</p>
            </div>
          )}

          {cameraOn && (
            <div className="webcam-wrapper mb-4">
              <Webcam
                ref={webcamRef}
                audio={false}
                screenshotFormat="image/jpeg"
                screenshotQuality={0.92}
                videoConstraints={{ facingMode: "user", width: 640, height: 480 }}
                mirrored={false}
                style={{ width: "100%", borderRadius: "12px", display: "block" }}
                onUserMediaError={() => toast.error("Camera access denied — please allow it in your browser")}
              />
              <div className="webcam-overlay">
                <div className="scan-line" />
                <div style={{
                  position: "absolute", top: "12%", left: "22%", right: "22%", bottom: "12%",
                  border: "2px dashed rgba(0,229,255,0.5)", borderRadius: "8px",
                  display: "flex", alignItems: "center", justifyContent: "center",
                  pointerEvents: "none",
                }}>
                  <span style={{
                    color: "rgba(0,229,255,0.8)", fontSize: "11px",
                    background: "rgba(0,0,0,0.55)", padding: "4px 10px", borderRadius: "4px",
                  }}>
                    Center face here
                  </span>
                </div>
              </div>
            </div>
          )}

          {snapshot && (
            <div className="snapshot-preview mb-4">
              <img src={snapshot} alt="Captured face" style={{ width: "100%", display: "block" }} />
              <div style={{
                background: "rgba(16,185,129,0.1)", padding: "8px 14px",
                fontSize: "13px", color: "var(--success)", display: "flex",
                alignItems: "center", gap: "8px",
              }}>
                ✅ Face photo captured — ready to register
              </div>
            </div>
          )}

          {/* ── camera buttons ── */}
          <div className="flex-row mb-4">
            {!cameraOn && (
              <button
                type="button"
                className="btn btn-secondary"
                onClick={() => { setCameraOn(true); setSnapshot(null); }}
              >
                📷 {snapshot ? "Retake Photo" : "Open Camera"}
              </button>
            )}
            {cameraOn && (
              <>
                <button type="button" className="btn btn-primary" onClick={capturePhoto}>
                  📸 Capture Photo
                </button>
                <button type="button" className="btn btn-secondary" onClick={() => setCameraOn(false)}>
                  ✕ Cancel
                </button>
              </>
            )}
          </div>

          {/* ── submit ── */}
          <button
            type="submit"
            className="btn btn-primary"
            disabled={loading}
            style={{ width: "100%" }}
          >
            {loading
              ? <><span className="spinner" /> Registering...</>
              : "✅ Register Student"
            }
          </button>
        </form>
      </div>

      {/* ── RIGHT: tips ── */}
      <div>
        <div className="card mb-4">
          <div className="card-title">📌 Registration Tips</div>
          <ul style={{ listStyle: "none", display: "flex", flexDirection: "column", gap: "12px" }}>
            {[
              ["💡", "Student must face the camera directly"],
              ["💡", "Use a well-lit area — avoid backlighting"],
              ["💡", "Only one person should be in the frame"],
              ["💡", "Remove glasses or hats if possible"],
              ["💡", "Look straight into the camera lens"],
            ].map(([icon, text], i) => (
              <li key={i} style={{ display: "flex", gap: "10px", color: "var(--text2)", fontSize: "14px" }}>
                <span>{icon}</span><span>{text}</span>
              </li>
            ))}
          </ul>
        </div>

        <div className="card">
          <div className="card-title">🔐 How It Works</div>
          <div style={{ display: "flex", flexDirection: "column", gap: "16px" }}>
            {[
              { step: "01", title: "Fill Details",   desc: "Enter Student ID, full name and course" },
              { step: "02", title: "Capture Face",   desc: "Open camera and take a clear photo" },
              { step: "03", title: "Register",       desc: "Face encoding is extracted and saved" },
              { step: "04", title: "Auto Attendance",desc: "Student is recognized instantly during class" },
            ].map(s => (
              <div key={s.step} style={{ display: "flex", gap: "14px", alignItems: "flex-start" }}>
                <div style={{
                  fontFamily: "Space Mono, monospace", fontSize: "11px", color: "var(--accent)",
                  background: "rgba(0,229,255,0.1)", padding: "4px 8px",
                  borderRadius: "6px", flexShrink: 0,
                }}>{s.step}</div>
                <div>
                  <div style={{ fontWeight: 600, fontSize: "14px" }}>{s.title}</div>
                  <div style={{ color: "var(--text3)", fontSize: "13px", marginTop: "2px" }}>{s.desc}</div>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>

    </div>
  );
}
